from typing import Any

from flask import Flask, Response, jsonify, request

app = Flask(__name__)


def error_response(message: str) -> tuple[Response, int]:
    return jsonify({"error": message}), 400


@app.post("/api/transform")
def transform_text() -> tuple[Response, int]:
    """Transform input text using the requested operation."""
    data: Any = request.get_json(silent=True)

    if data is None:
        return error_response("Request body must be valid JSON")

    if not isinstance(data, dict):
        return error_response("Request body must be a JSON object")

    text = data.get("text")
    if not isinstance(text, str):
        return error_response('The "text" field is required and must be a string')

    operation = data.get("operation")
    if operation not in {"uppercase", "reverse", "count_words"}:
        return error_response(
            'The "operation" field is required and must be one of: uppercase, reverse, count_words'
        )

    if operation == "uppercase":
        result: str | int = text.upper()
    elif operation == "reverse":
        result = text[::-1]
    else:
        result = len(text.split())

    return jsonify(
        {
            "result": result,
            "operation": operation,
            "original_length": len(text),
        }
    ), 200


if __name__ == "__main__":
    app.run(debug=True, port=5000)
